"use client";

import { useState } from "react";
import Link from "next/link";
import { StylePreview } from "@/components/StylePreview";
import { WearButton } from "@/components/WearButton";

type Tab = "preview" | "skill" | "pages" | "corpus";

interface Props {
  style: {
    id: string;
    slug: string;
    name: string;
    description: string | null;
    authorName: string;
    authorUrl: string | null;
    skillContent: string;
    previewHtml: string | null;
    forkedFromId: string | null;
    tags: string | null;
    likesCount: number;
    forksCount: number;
    createdAt: string;
    updatedAt: string;
  };
  pages: {
    id: string;
    pageType: string;
    htmlContent: string;
    screenshotUrl: string | null;
  }[];
  images: {
    id: string;
    url: string;
    caption: string | null;
  }[];
  forkedFromName: string | null;
}

export function StyleDetailClient({ style, pages, images, forkedFromName }: Props) {
  const [tab, setTab] = useState<Tab>("preview");
  const tags = style.tags ? style.tags.split(",").map((t) => t.trim()).filter(Boolean) : [];

  const tabs: { key: Tab; label: string }[] = [
    { key: "preview", label: "Preview" },
    { key: "skill", label: "Skill File" },
    { key: "pages", label: "Pages" },
    { key: "corpus", label: "Corpus" },
  ];

  return (
    <div className="max-w-7xl mx-auto px-6 py-12">
      <div className="flex flex-col md:flex-row md:items-start md:justify-between gap-6 mb-8">
        <div>
          <h1 className="text-3xl font-bold">{style.name}</h1>
          {style.description && (
            <p className="text-neutral-400 mt-2 max-w-2xl">{style.description}</p>
          )}
          <div className="flex items-center gap-4 mt-3 text-sm text-neutral-500">
            <span>by {style.authorName}</span>
            <span>{style.likesCount} likes</span>
            <span>{style.forksCount} forks</span>
          </div>
          {forkedFromName && style.forkedFromId && (
            <Link
              href={`/style/${style.forkedFromId}`}
              className="inline-block mt-2 text-xs px-3 py-1 rounded-full bg-purple-900/30 text-purple-300 border border-purple-800/50"
            >
              Forked from {forkedFromName}
            </Link>
          )}
          {tags.length > 0 && (
            <div className="flex flex-wrap gap-1.5 mt-3">
              {tags.map((tag) => (
                <span key={tag} className="text-xs px-2 py-0.5 rounded-full bg-neutral-800 text-neutral-400">
                  {tag}
                </span>
              ))}
            </div>
          )}
        </div>
        <div className="flex gap-3">
          <WearButton styleId={style.id} slug={style.slug} name={style.name} />
          <Link
            href={`/style/${style.id}/fork`}
            className="px-5 py-2.5 rounded-lg bg-purple-600 hover:bg-purple-500 text-white text-sm font-medium transition-colors"
          >
            Fork This Style
          </Link>
          <a
            href={`data:text/markdown;charset=utf-8,${encodeURIComponent(style.skillContent)}`}
            download={`${style.name}.md`}
            className="px-5 py-2.5 rounded-lg border border-neutral-700 hover:border-neutral-500 text-neutral-300 text-sm font-medium transition-colors"
          >
            Download Skill
          </a>
        </div>
      </div>

      <div className="mb-8 p-3 rounded-lg bg-neutral-900 border border-neutral-800 flex items-center gap-3">
        <span className="text-xs text-neutral-500">CLI:</span>
        <code className="text-xs text-neutral-300 font-mono">drip get {style.slug}</code>
      </div>

      <div className="flex gap-1 border-b border-neutral-800 mb-8">
        {tabs.map((t) => (
          <button
            key={t.key}
            onClick={() => setTab(t.key)}
            className={`px-4 py-2.5 text-sm font-medium transition-colors border-b-2 -mb-px ${
              tab === t.key
                ? "border-purple-500 text-white"
                : "border-transparent text-neutral-500 hover:text-neutral-300"
            }`}
          >
            {t.label}
          </button>
        ))}
      </div>

      {tab === "preview" && (
        <div className="rounded-xl border border-neutral-800 overflow-hidden bg-white">
          {style.previewHtml ? (
            <StylePreview html={style.previewHtml} className="w-full h-[600px]" />
          ) : (
            <div className="h-[600px] flex items-center justify-center text-neutral-500">
              No preview available
            </div>
          )}
        </div>
      )}

      {tab === "skill" && (
        <pre className="p-6 rounded-xl bg-neutral-900 border border-neutral-800 text-sm text-neutral-300 overflow-x-auto whitespace-pre-wrap font-mono leading-relaxed">
          {style.skillContent}
        </pre>
      )}

      {tab === "pages" && (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          {pages.length === 0 ? (
            <p className="text-neutral-500 col-span-3">No pages yet.</p>
          ) : (
            pages.map((page) => (
              <div
                key={page.id}
                className="rounded-xl border border-neutral-800 overflow-hidden bg-neutral-900"
              >
                <div className="aspect-[4/3] bg-white overflow-hidden">
                  <StylePreview
                    html={page.htmlContent}
                    className="w-full h-full pointer-events-none"
                  />
                </div>
                <div className="p-4 flex items-center justify-between">
                  <span className="text-sm font-medium capitalize">{page.pageType}</span>
                  <button
                    onClick={() => {
                      const w = window.open("", "_blank");
                      if (w) {
                        w.document.write(page.htmlContent);
                        w.document.close();
                      }
                    }}
                    className="text-xs text-purple-400 hover:text-purple-300"
                  >
                    View Full
                  </button>
                </div>
              </div>
            ))
          )}
        </div>
      )}

      {tab === "corpus" && (
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
          {images.length === 0 ? (
            <p className="text-neutral-500 col-span-4">No corpus images.</p>
          ) : (
            images.map((img) => (
              <div key={img.id} className="rounded-lg overflow-hidden border border-neutral-800">
                <img src={img.url} alt={img.caption || ""} className="w-full aspect-square object-cover" />
                {img.caption && (
                  <p className="p-2 text-xs text-neutral-500">{img.caption}</p>
                )}
              </div>
            ))
          )}
        </div>
      )}
    </div>
  );
}
